import pytest
import requests

BASE_URL = "http://fhir-lite/fhir/R4"
BOUNDARY_TS = "2024-01-01T00:00:00Z"

@pytest.fixture
def prescriber_token():
    return <fixture: get_prescriber_bearer_token>

def test_create_medication_request_authored_on_exact_rfc3339_no_subseconds(prescriber_token):
    payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "medicationCodeableConcept": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                        "code": "835603", "display": "Ibuprofen 200 MG"}]
        },
        "subject": {"reference": "Patient/test-patient-001"},
        "authoredOn": BOUNDARY_TS,
        "requester": {"reference": "Practitioner/test-prescriber-001"},
        "dispenseRequest": {"quantity": {"value": 10, "unit": "tablet"}}
    }
    headers = {"Authorization": f"Bearer {prescriber_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/MedicationRequest", json=payload, headers=headers)
    assert resp.status_code == 201
    resource_id = resp.json()["id"]
    get_resp = requests.get(f"{BASE_URL}/MedicationRequest/{resource_id}", headers=headers)
    assert get_resp.status_code == 200
    stored_ts = get_resp.json().get("authoredOn", "")
    assert stored_ts.startswith("2024-01-01T00:00:00")
